commit f07dbbe676c6ad47c4f9747fcfe0d520434d3fde
Author: Audra Mitchell <audra@redhat.com>
selftests/mm: Fix soft-dirty kselftest supported check

This commit simplifies the PAGEMAP_SCAN support check to avoid false
failures on architectures with separate user address spaces or without an
MMU. It achieves this by mapping a valid test page and checking if the ioctl
succeeds rather than intentionally passing an invalid address to test for
EFAULT.

> diff --git a/tools/testing/selftests/mm/vm_util.c b/tools/testing/selftests/mm/vm_util.c
> index a6d4ff7dfdc0..82998406b335 100644
> --- a/tools/testing/selftests/mm/vm_util.c
> +++ b/tools/testing/selftests/mm/vm_util.c
[ ... ]
> @@ -67,20 +67,26 @@ static uint64_t pagemap_scan_get_categories(int fd, char *start)
>  }
>  
>  /* `start` is any valid address. */
> -static bool pagemap_scan_supported(int fd, char *start)
> +static bool pagemap_scan_supported(int fd)
>  {
> +	const size_t pagesize = getpagesize();
>  	static int supported = -1;
> -	int ret;
> +	struct page_region r;
> +	void *test_area;
>  
>  	if (supported != -1)
>  		return supported;
>  
> -	/* Provide an invalid address in order to trigger EFAULT. */
> -	ret = __pagemap_scan_get_categories(fd, start, (struct page_region *) ~0UL);
> -	if (ret == 0)
> -		ksft_exit_fail_msg("PAGEMAP_SCAN succeeded unexpectedly\n");
> -
> -	supported = errno == EFAULT;
> +	test_area = mmap(0, pagesize, PROT_READ | PROT_WRITE,
> +			MAP_ANONYMOUS | MAP_PRIVATE, 0, 0);

This isn't a bug, but while Linux ignores the file descriptor argument when
MAP_ANONYMOUS is provided, standard POSIX practice is to pass -1 instead of
0 to avoid ambiguity with standard input. Should this use -1 instead?

> +	if (test_area == MAP_FAILED) {
> +		ksft_print_msg("WARN: mmap() failed: %s\n", strerror(errno));
> +		supported = 0;
> +	} else {
> +		supported = __pagemap_scan_get_categories(fd, test_area, &r) >= 0;

Does this condition always evaluate to true?

Looking at __pagemap_scan_get_categories(), it is defined as returning a
uint64_t. If the PAGEMAP_SCAN ioctl is not supported and returns -1, it will
be implicitly cast to UINT64_MAX. Because the return value is unsigned, the
comparison >= 0 evaluates to true instead of false.

> +		ksft_print_msg("errno: %d\n", errno);

Could this unconditionally print a stale error value?

If the ioctl succeeds, errno is not reset, which could lead to printing a
value left over from a previous failed system call in the thread and clutter
the test logs.

> +		munmap(test_area, pagesize);
> +	}
>  
>  	return supported;
>  }

